INSERT INTO `feedbacks` (`id`, `user_id`, `type`, `message`, `admin_response`, `responded_at`, `status`, `is_deleted`, `deleted_at`, `created_at`, `updated_at`) VALUES
(1, 19, 'GENERAL', 'Try to add a pdf to take printout', 'Thank you for the feedback. We’re actively working on the PDF print functionality and testing it in multiple scenarios. We’ll keep you posted with an update soon.', '2026-03-03 19:10:32', 'RESOLVED', 0, NULL, '2026-03-03 07:42:01', '2026-07-06 14:26:56'),
(2, 11, 'GENERAL', 'ஒருவர் இரண்டாம் முறை விசேஷம் வைத்தால் தனியாக சேமிக்க வேண்டுமா.. ஒரே பெயரில் மேலும் சேர்க்க முடியாதா?', 'உங்களது கருத்துக்களை தெரியப்படுத்தியதற்கு நன்றி மற்றும் உங்களது கருத்துக்கள் நிறைவேற்றப்பட்டது. தயவு செய்து சரிபார்த்து தெரியப்படுத்தவும்.', '2026-03-16 21:40:56', 'RESOLVED', 0, NULL, '2026-03-03 07:41:37', '2026-07-06 14:26:56');
