(9, 33, 'பயனர் வெற்றிகரமாக பதிவு செய்யப்பட்டார்', 'இப்போது நீங்கள் இந்த பயன்பாட்டைப் பயன்படுத்தலாம்', 'account', 0, NULL, '2026-03-12 22:47:24', '2026-07-06 19:59:17', 0, NULL),
(12, 20, 'புதிய கருத்து சமர்ப்பிக்கப்பட்டது', 'உங்கள் கருத்து வெற்றிகரமாக சமர்ப்பிக்கப்பட்டது. நாங்கள் விரைவில் மதிப்பாய்வு செய்வோம்.', 'general', 0, NULL, '2026-03-07 04:48:32', '2026-07-06 19:59:17', 0, NULL),
(21, 33, 'கடவுச்சொல் மீட்டமைக்கப்பட்டது', 'உங்கள் கடவுச்சொல் வெற்றிகரமாக மீட்டமைக்கப்பட்டது. உங்கள் கணக்கின் பாதுகாப்பை உறுதிப்படுத்த, வழக்கமாக கடவுச்சொல்லை மாற்றவும்.', 'account', 0, NULL, '2026-03-13 15:52:13', '2026-07-06 19:59:17', 0, NULL),
